/* ---------------- reveal-on-scroll wrapper ---------------- */
function Reveal({ children, className = "", delay = 0 }) {
  const ref = useRef(null);
  const [shown, setShown] = useState(false);
  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const io = new IntersectionObserver(
      ([entry]) => { if (entry.isIntersecting) { setShown(true); io.disconnect(); } },
      { threshold: 0.15 }
    );
    io.observe(el);
    return () => io.disconnect();
  }, []);
  return (
    <div
      ref={ref}
      className={className}
      style={{
        opacity: shown ? 1 : 0,
        transform: shown ? "translateY(0)" : "translateY(28px)",
        transition: `opacity .7s ease ${delay}ms, transform .7s ease ${delay}ms`,
      }}
    >
      {children}
    </div>
  );
}

/* ---------------- animated counter ---------------- */
function Counter({ value, suffix = "" }) {
  const ref = useRef(null);
  const [n, setN] = useState(0);
  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    let started = false;
    const io = new IntersectionObserver(([entry]) => {
      if (entry.isIntersecting && !started) {
        started = true;
        const start = performance.now();
        const dur = 1200;
        const tick = (t) => {
          const p = Math.min(1, (t - start) / dur);
          setN(Math.floor(p * value));
          if (p < 1) requestAnimationFrame(tick);
          else setN(value);
        };
        requestAnimationFrame(tick);
        io.disconnect();
      }
    }, { threshold: 0.4 });
    io.observe(el);
    return () => io.disconnect();
  }, [value]);
  return <span ref={ref}>{n}{suffix}</span>;
}

/* ---------------- typed / rotating role text ---------------- */
function TypedRoles({ roles }) {
  const [text, setText] = useState("");
  const [idx, setIdx] = useState(0);
  const [deleting, setDeleting] = useState(false);
  useEffect(() => {
    const full = roles[idx % roles.length];
    const speed = deleting ? 35 : 65;
    const pause = 1400;
    let t;
    if (!deleting && text === full) {
      t = setTimeout(() => setDeleting(true), pause);
    } else if (deleting && text === "") {
      setDeleting(false);
      setIdx((i) => i + 1);
    } else {
      t = setTimeout(() => {
        setText(full.slice(0, text.length + (deleting ? -1 : 1)));
      }, speed);
    }
    return () => clearTimeout(t);
  }, [text, deleting, idx, roles]);
  return (
    <span style={{ color: "var(--green)" }}>
      {text}
      <span className="pt-caret">_</span>
    </span>
  );
}

/* ---------------- particle network background (canvas) ---------------- */
function ParticleField() {
  const canvasRef = useRef(null);
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    let raf, w, h, particles;

    const init = () => {
      w = canvas.width = canvas.offsetWidth;
      h = canvas.height = canvas.offsetHeight;
      const count = Math.min(55, Math.floor((w * h) / 22000));
      particles = Array.from({ length: count }, () => ({
        x: Math.random() * w,
        y: Math.random() * h,
        vx: (Math.random() - 0.5) * 0.35,
        vy: (Math.random() - 0.5) * 0.35,
      }));
    };

    const step = () => {
      ctx.clearRect(0, 0, w, h);
      particles.forEach((p) => {
        p.x += p.vx; p.y += p.vy;
        if (p.x < 0 || p.x > w) p.vx *= -1;
        if (p.y < 0 || p.y > h) p.vy *= -1;
      });
      for (let i = 0; i < particles.length; i++) {
        for (let j = i + 1; j < particles.length; j++) {
          const a = particles[i], b = particles[j];
          const d = Math.hypot(a.x - b.x, a.y - b.y);
          if (d < 130) {
            ctx.strokeStyle = `rgba(255,42,69,${0.14 * (1 - d / 130)})`;
            ctx.lineWidth = 1;
            ctx.beginPath();
            ctx.moveTo(a.x, a.y); ctx.lineTo(b.x, b.y);
            ctx.stroke();
          }
        }
      }
      particles.forEach((p) => {
        ctx.fillStyle = "rgba(0,200,255,0.55)";
        ctx.beginPath();
        ctx.arc(p.x, p.y, 1.6, 0, Math.PI * 2);
        ctx.fill();
      });
      raf = requestAnimationFrame(step);
    };

    init();
    step();
    const onResize = () => init();
    window.addEventListener("resize", onResize);
    return () => { cancelAnimationFrame(raf); window.removeEventListener("resize", onResize); };
  }, []);
  return <canvas ref={canvasRef} className="pt-particles" />;
}

/* ---------------- 3D tilt card ---------------- */
function TiltCard({ children, className = "", style = {} }) {
  const ref = useRef(null);
  const [tilt, setTilt] = useState({ rx: 0, ry: 0 });
  const onMove = (e) => {
    const el = ref.current;
    if (!el) return;
    const r = el.getBoundingClientRect();
    const px = (e.clientX - r.left) / r.width - 0.5;
    const py = (e.clientY - r.top) / r.height - 0.5;
    setTilt({ rx: py * -8, ry: px * 8 });
  };
  const onLeave = () => setTilt({ rx: 0, ry: 0 });
  return (
    <div
      ref={ref}
      onMouseMove={onMove}
      onMouseLeave={onLeave}
      className={className}
      style={{
        ...style,
        transform: `perspective(700px) rotateX(${tilt.rx}deg) rotateY(${tilt.ry}deg)`,
        transition: "transform .15s ease",
      }}
    >
      {children}
    </div>
  );
}

/* ---------------- interactive terminal ---------------- */
function InteractiveTerminal({ onNavigate }) {
  const [lines, setLines] = useState([
    "muthumari@security:~$ Welcome. Type 'help' to get started.",
  ]);
  const [cmd, setCmd] = useState("");
  const boxRef = useRef(null);

  useEffect(() => {
    if (boxRef.current) boxRef.current.scrollTop = boxRef.current.scrollHeight;
  }, [lines]);

  const run = (raw) => {
    const c = raw.trim().toLowerCase();
    const out = [`muthumari@security:~$ ${raw}`];
    switch (c) {
      case "help":
        out.push(...TERMINAL_HELP);
        break;
      case "whoami":
        out.push("Muthumari B — Offensive Security Engineer & Penetration Tester.", "3+ years in IT, 2 years focused in pentesting. Web, API & network security.");
        break;
      case "skills":
        out.push("Burp Suite · Nmap · Metasploit · OWASP ZAP · Nessus · Python · Bash · Kali Linux");
        break;
      case "experience":
        out.push("2 years penetration testing: web app, API & network assessments mapped to OWASP Top 10.");
        onNavigate("experience");
        break;
      case "projects":
        out.push("Loading project index...");
        onNavigate("projects");
        break;
      case "contact":
        out.push("Opening contact channel...");
        onNavigate("contact");
        break;
      case "resume":
        out.push("Opening resume...");
        setLines((L) => [...L, ...out]);
        setCmd("");
        const a = document.createElement("a");
        a.href = RESUME_PDF;
        a.download = "Muthumari_B_Resume.pdf";
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        return;
      case "clear":
        setLines([]);
        setCmd("");
        return;
      case "":
        return;
      default:
        out.push(`command not found: ${c} — type 'help' for a list of commands`);
    }
    setLines((L) => [...L, ...out]);
    setCmd("");
  };

  return (
    <div className="pt-term">
      <div className="pt-term-head">
        <span className="pt-dot" style={{ background: "#ff5f56" }} />
        <span className="pt-dot" style={{ background: "#ffbd2e" }} />
        <span className="pt-dot" style={{ background: "#27c93f" }} />
        <span className="pt-term-title">muthumari@security: ~</span>
      </div>
      <div ref={boxRef} className="pt-term-body">
        {lines.map((l, i) => (
          <div key={i} className="pt-term-line">{l}</div>
        ))}
        <div className="pt-term-line pt-term-input-row">
          <span style={{ color: "var(--green)" }}>muthumari@security:~$&nbsp;</span>
          <input
            value={cmd}
            onChange={(e) => setCmd(e.target.value)}
            onKeyDown={(e) => e.key === "Enter" && run(cmd)}
            spellCheck={false}
            autoComplete="off"
            className="pt-term-input"
            placeholder="type a command..."
          />
        </div>
      </div>
    </div>
  );
}

